const query = $json.query || {};

const clusters = {
  clab: { testId: '7719616' },
  klab: { testId: '7719618' },
  emerald: { testId: '7719620' },
  gold: { testId: '7719621' },
  golddr: { testId: '7719622' },
  silver: { testId: '7719640' },
};

const testIdToCluster = Object.fromEntries(Object.entries(clusters).map(([cluster, cfg]) => [cfg.testId, cluster]));

let cluster = query.cluster ? String(query.cluster).toLowerCase() : '';
if (!cluster && query.test_id && testIdToCluster[String(query.test_id)]) {
  cluster = testIdToCluster[String(query.test_id)];
}
if (!clusters[cluster]) cluster = 'silver';

let days = parseInt(String(query.days || '30'), 10);
if (!Number.isFinite(days) || days < 1) days = 30;
if (days > 3650) days = 3650;

const includeInvalid = ['1', 'true', 'yes'].includes(String(query.include_invalid || '').toLowerCase());
const safeCluster = cluster.replace(/'/g, "''");
const validFilter = includeInvalid ? '' : '    AND d.is_valid = true';

const sql = [
  'WITH params AS (',
  "  SELECT now() AS end_ts, now() - interval '" + days + " days' AS start_ts, " + (days * 24 * 60 * 60) + '::numeric AS window_seconds',
  '), overlap AS (',
  '  SELECT COALESCE(SUM(EXTRACT(EPOCH FROM (LEAST(d.ended_at, p.end_ts) - GREATEST(d.started_at, p.start_ts)))), 0)::numeric AS down_seconds',
  '  FROM params p',
  '  LEFT JOIN public.statuscake_downtime_periods d',
  "    ON d.cluster = '" + safeCluster + "'",
  '   AND d.started_at < p.end_ts',
  '   AND d.ended_at > p.start_ts',
  validFilter,
  '), point AS (',
  '  SELECT',
  '    p.end_ts AS bucket_ts,',
  '    GREATEST(0, LEAST(100, ROUND((100 * (1 - (o.down_seconds / NULLIF(p.window_seconds, 0))))::numeric, 4))) AS uptime_percentage,',
  '    ROUND(o.down_seconds::numeric, 0) AS downtime_seconds',
  '  FROM params p CROSS JOIN overlap o',
  ')',
  'SELECT bucket_ts, uptime_percentage, downtime_seconds FROM point;'
].filter((line) => line !== '').join('\n');

return [{ json: { cluster, testId: clusters[cluster].testId, days, includeInvalid, sql } }];

const rows = $input.all().filter((item) => item.json && item.json.bucket_ts !== undefined);
const row = rows[0]?.json || {};
const timestamp = row.bucket_ts instanceof Date ? row.bucket_ts.toISOString() : new Date(row.bucket_ts || Date.now()).toISOString();
const value = Number(row.uptime_percentage ?? 100);

return [{
  json: {
    data: [
      { timestamp, value }
    ]
  }
}];
